steps.script:
() => {
  const btn = document.querySelector('.ml-hero__btn');
  const out = {url: location.href, theme: (window.Shopify&&Shopify.theme)||null};
  if(!btn){ out.error='no .ml-hero__btn'; return out; }
  const cs = getComputedStyle(btn);
  out.classes = btn.className;
  out.computed = {bg: cs.backgroundColor, bgImage: cs.backgroundImage, color: cs.color, radius: cs.borderRadius, fontSize: cs.fontSize};
  out.rules = [];
  const walk = (rules, src) => {
    for (const r of rules){
      if(r.type===4){ try{walk(r.cssRules, src+' @media('+r.conditionText+')');}catch(e){} continue; }
      if(!r.selectorText||!r.style) continue;
      const bg = r.style.getPropertyValue('background') || r.style.getPropertyValue('background-color');
      if(!bg) continue;
      let m=false; try{ m=btn.matches(r.selectorText.replace(/::(before|after|marker|placeholder|selection)/g,'')); }catch(e){}
      if(m){ out.rules.push({sel:r.selectorText, bg:bg, prio:r.style.getPropertyPriority('background-color')||r.style.getPropertyPriority('background')||'', src:src}); }
    }
  };
  for(const s of document.styleSheets){ let rs; try{rs=s.cssRules;}catch(e){ out.rules.push({sel:'[CORS]',src:s.href}); continue;} walk(rs, s.href||'inline'); }
  return out;
}

() => {
  const btn = document.querySelector('.ml-hero__btn');
  return {
    url: location.href,
    theme: (window.Shopify&&Shopify.theme)||null,
    btnBg: btn?getComputedStyle(btn).backgroundColor:null,
    btnRadius: btn?getComputedStyle(btn).borderRadius:null,
    btnFontSize: btn?getComputedStyle(btn).fontSize:null,
    hasMauveInDom: document.documentElement.innerHTML.indexOf('#9e4c58')>=0
  };
}
